import { useState, useEffect } from 'react';
import API from '../Api/Axios';
import './Usage.css';

const Usage = () => {
  const [filterType, setFilterType] = useState('month'); // 'month' | 'range' | 'all'
  const [month, setMonth] = useState(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  });
  const [from, setFrom] = useState('');
  const [to, setTo] = useState('');

  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchUsage = async () => {
    setLoading(true);
    setError('');
    try {
      let params = {};
      if (filterType === 'month') params.month = month;
      else if (filterType === 'range') {
        if (from) params.from = from;
        if (to) params.to = to;
      }

      const { data: res } = await API.get('/usage', { params });
      setData(res);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load usage data');
    } finally {
      setLoading(false);
    }
  };

  // Auto-fetch on mount and when filterType/month changes
  useEffect(() => {
    if (filterType === 'month' && month) fetchUsage();
    if (filterType === 'all') fetchUsage();
    // For range, user clicks Apply
  }, [filterType, month]);

  const handleApplyRange = () => {
    if (!from && !to) return;
    fetchUsage();
  };

  const formatMonth = (m) => {
    if (!m) return '';
    const [y, mo] = m.split('-');
    const d = new Date(y, mo - 1);
    return d.toLocaleString('en-PK', { month: 'long', year: 'numeric' });
  };

  return (
    <div className="usage-page">
      {/* Header */}
      <div className="usage-header">
        <h1>Ingredient Usage</h1>
        <p className="usage-sub">Track how much of each ingredient is consumed based on sales</p>
      </div>

      {/* Filter Bar */}
      <div className="usage-filter-bar">
        {/* Filter Type Tabs */}
        <div className="usage-tabs">
          <button
            className={`usage-tab ${filterType === 'month' ? 'active' : ''}`}
            onClick={() => setFilterType('month')}
          >
            Monthly
          </button>
          <button
            className={`usage-tab ${filterType === 'range' ? 'active' : ''}`}
            onClick={() => setFilterType('range')}
          >
            Date Range
          </button>
          <button
            className={`usage-tab ${filterType === 'all' ? 'active' : ''}`}
            onClick={() => setFilterType('all')}
          >
            All Time
          </button>
        </div>

        {/* Filter Inputs */}
        <div className="usage-filter-inputs">
          {filterType === 'month' && (
            <input
              type="month"
              className="usage-input"
              value={month}
              onChange={(e) => setMonth(e.target.value)}
            />
          )}

          {filterType === 'range' && (
            <div className="usage-range">
              <input
                type="date"
                className="usage-input"
                value={from}
                onChange={(e) => setFrom(e.target.value)}
                placeholder="From"
              />
              <span className="usage-range-sep">→</span>
              <input
                type="date"
                className="usage-input"
                value={to}
                onChange={(e) => setTo(e.target.value)}
                placeholder="To"
              />
              <button className="usage-apply-btn" onClick={handleApplyRange}>
                Apply
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Stats Bar */}
      {data && !loading && (
        <div className="usage-stats-bar">
          <div className="usage-stat">
            <span className="stat-number">{data.totalInvoices}</span>
            <span className="stat-label">Invoices</span>
          </div>
          <div className="usage-stat">
            <span className="stat-number">{data.ingredients.length}</span>
            <span className="stat-label">Ingredients Used</span>
          </div>
          <div className="usage-stat">
            <span className="stat-label-big">
              {filterType === 'month'
                ? formatMonth(month)
                : filterType === 'range'
                ? `${from || '—'} to ${to || '—'}`
                : 'All Time'}
            </span>
          </div>
        </div>
      )}

      {/* Content */}
      <div className="usage-content">
        {loading && (
          <div className="usage-loader">
            <div className="usage-spinner" />
            <span>Calculating usage...</span>
          </div>
        )}

        {error && !loading && (
          <div className="usage-error">{error}</div>
        )}

        {!loading && !error && data && data.ingredients.length === 0 && (
          <div className="usage-empty">
            <span className="usage-empty-icon">📦</span>
            <p>No sales found for this period</p>
            <span>Try selecting a different month or date range</span>
          </div>
        )}

        {!loading && !error && data && data.ingredients.length > 0 && (
          <div className="usage-table-wrap">
            <table className="usage-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Ingredient</th>
                  <th>Total Used</th>
                  <th>Unit</th>
                  <th>Used In (Items)</th>
                </tr>
              </thead>
              <tbody>
                {data.ingredients.map((ing, i) => (
                  <tr key={`${ing.name}-${ing.unit}`}>
                    <td className="usage-num">{i + 1}</td>
                    <td className="usage-ing-name">{ing.name}</td>
                    <td className="usage-qty">
                      <span className="qty-badge">{ing.totalQuantity.toFixed(2)}</span>
                    </td>
                    <td className="usage-unit">{ing.unit}</td>
                    <td className="usage-items">
                      {ing.usedInItems.map((u, j) => (
                        <span key={j} className="used-in-chip">
                          {u.menuItem} ×{u.qtySold}
                        </span>
                      ))}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default Usage;
